#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<long long>a(n);for(auto&x:a)scanf("%lld",&x);sort(a.begin(),a.end());int q;scanf("%d",&q);string out;while(q--){long long x;scanf("%lld",&x);out+=to_string((long long)(upper_bound(a.begin(),a.end(),x)-a.begin()));out+='\n';}fputs(out.c_str(),stdout);}
